// CONSTANT INDEX

// CHECK-LABEL: @subscript_const_i32(
// CHECK-NEXT:  entry:
// CHECK-NEXT:    [[VECEXT:%.*]] = extractelement <vscale x 2 x i32> [[A:%.*]], i32 0
// CHECK-NEXT:    ret i32 [[VECEXT]]
//
int subscript_const_i32(vint32m1_t a) {
  return a[0];
}

// CHECK-LABEL: @subscript_const_store_i32(
// CHECK-NEXT:  entry:
// CHECK-NEXT:    [[VECINS:%.*]] = insertelement <vscale x 2 x i32> [[A:%.*]], i32 [[VAL:%.*]], i32 1
// CHECK-NEXT:    ret <vscale x 2 x i32> [[VECINS]]
//
vint32m1_t subscript_const_store_i32(vint32m1_t a, int val) {
  a[1] = val;
  return a;
}

